import { useFrame } from '@react-three/fiber';

function Box({ position, color = 'orange', onToggle }) {
  const ref = useRef();
  const [hovered, hover] = useState(false);
  const [clicked, click] = useState(false);

  useFrame((state, delta) => (ref.current.rotation.x += delta));

  return (
    <mesh
      position={position}
      ref={ref}
      scale={clicked ? 1.5 : 1}
      onClick={() => {
        click(!clicked);
        if (onToggle) onToggle(!clicked);
      }}
      onPointerOver={(e) => (e.stopPropagation(), hover(true))}
      onPointerOut={() => hover(false)}
    >
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color={hovered ? 'hotpink' : color} />
    </mesh>
  );
}

function StatusBar({ leftColor, rightColor, clickCount }) {
  return (
    <div className="px-6 py-4 bg-zinc-900/50 border-t border-zinc-800/50 flex items-center gap-6 flex-wrap">
      <Stat label="Left box">
        <span className="w-4 h-4 rounded-full border border-zinc-700" style={{ backgroundColor: leftColor }} />
      </Stat>
      <Stat label="Right box">
        <span className="w-4 h-4 rounded-full border border-zinc-700" style={{ backgroundColor: rightColor }} />
      </Stat>
      <Stat label="Clicks">
        <span className="text-sm font-mono text-cyan-400">{clickCount}</span>
      </Stat>
    </div>
  );
}

