import { Canvas } from '@react-three/fiber';
import { OrbitControls } from '@react-three/drei';

function App() {
  const { data, send } = useNodeRed();
  const colors = data || { leftColor: 'orange', rightColor: 'cyan' };
  const [clickCount, setClickCount] = useState(0);

  const handleToggle = useCallback((clicked) => {
    setClickCount(prev => prev + 1);
    send({ action: clicked ? 'clicked' : 'unclicked', clicks: clickCount + 1 }, '3d/interact');
  }, [send, clickCount]);

  return (
    <div className="h-screen bg-zinc-950 text-zinc-100 flex flex-col">
      <Header title="fromcubes 3D" subtitle="React Three Fiber + live Node-RED data" />
      <div className="flex-1 overflow-hidden">
        <Canvas style={{ width: '100%', height: '100%' }}>
          <ambientLight intensity={Math.PI / 2} />
          <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} decay={0} intensity={Math.PI} />
          <pointLight position={[-10, -10, -10]} decay={0} intensity={Math.PI} />
          <Box position={[-1.2, 0, 0]} color={colors.leftColor} onToggle={handleToggle} />
          <Box position={[1.2, 0, 0]} color={colors.rightColor} onToggle={handleToggle} />
          <OrbitControls />
        </Canvas>
      </div>
      <StatusBar leftColor={colors.leftColor} rightColor={colors.rightColor} clickCount={clickCount} />
    </div>
  );
}
